// Capture required email metadata for the audit trail and downstream nodes
const meta = {
  sender: $json.from || $json.headers?.from || '',
  senderEmail: (($json.from || '').match(/<(.+)>/) || [null, $json.from])[1],
  senderName: (($json.from || '').split('<')[0] || '').trim(),
  subject: $json.subject || '',
  receivedAt: $json.date || new Date().toISOString()
};
return [{ json: { ...$json, emailMeta: meta }, binary: $binary }];

