// Step 4: Data Cleaning - safely parse, strip fences defensively, validate, and normalize the AI response
let raw = $json.content?.[0]?.text || '{}';
raw = raw.trim().replace(/^```json/i, '').replace(/^```/, '').replace(/```$/, '').trim();

let data;
try {
  data = JSON.parse(raw);
} catch (e) {
  return [{ json: { extractionError: true, errorMessage: 'Failed to parse AI JSON: ' + e.message, rawResponse: raw } }];
}

const num = (v) => {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(v);
  return isNaN(n) ? null : n;
};

const cleanLineItems = (Array.isArray(data.line_items) ? data.line_items : [])
  .filter(li => li && (li.description || '').trim().length > 0)
  .map(li => ({
    description: (li.description || '').trim(),
    quantity: num(li.quantity),
    unit_price: num(li.unit_price),
    line_total: num(li.line_total)
  }));

const anomalies = Array.isArray(data.anomalies) ? data.anomalies : [];

// Cross-check math and append anomalies the AI may have missed
const net = num(data.net_amount), vat = num(data.vat_amount), gross = num(data.gross_amount);
if (net !== null && vat !== null && gross !== null && Math.abs((net + vat) - gross) > 0.02) {
  anomalies.push('Net + VAT does not equal Gross Amount (validation check)');
}

const cleaned = {
  vendor: data.vendor || null,
  vendor_uid: data.vendor_uid || null,
  vendor_iban: data.vendor_iban || null,
  invoice_number: data.invoice_number || null,
  invoice_date: data.invoice_date || null,
  due_date: data.due_date || null,
  net_amount: net,
  vat_amount: vat,
  vat_percent: num(data.vat_percent),
  gross_amount: gross,
  currency: data.currency || null,
  cost_center: data.cost_center || null,
  line_items: cleanLineItems,
  confidence_score: num(data.confidence_score) ?? 0,
  anomalies
};

return [{ json: { ...cleaned, extractionError: false } }];
